#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::Arc;
    use std::thread;

    #[test]
    fn test_concurrent_cell_basic() {
        let cell = ConcurrentCell::new(42);
        {
            let guard = cell.read().unwrap();
            assert_eq!(*guard, 42);
        }
        {
            let mut guard = cell.write().unwrap();
            *guard = 100;
        }
        {
            let guard = cell.read().unwrap();
            assert_eq!(*guard, 100);
        }
    }

    #[test]
    fn test_concurrent_cell_multiple_readers() {
        let cell = Arc::new(ConcurrentCell::new(vec![1, 2, 3]));
        let mut handles = vec![];

        for _ in 0..10 {
            let cell = Arc::clone(&cell);
            handles.push(thread::spawn(move || {
                let guard = cell.read().unwrap();
                assert_eq!(guard.len(), 3);
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }
    }

    #[test]
    fn test_concurrent_cell_writer_exclusion() {
        let cell = Arc::new(ConcurrentCell::new(0u64));
        let mut handles = vec![];

        for _ in 0..10 {
            let cell = Arc::clone(&cell);
            handles.push(thread::spawn(move || {
                for _ in 0..1000 {
                    let mut guard = cell.write().unwrap();
                    let val = *guard;
                    *guard = val + 1;
                }
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }

        let guard = cell.read().unwrap();
        assert_eq!(*guard, 10_000);
    }

    #[test]
    fn test_concurrent_stack_basic() {
        let stack = ConcurrentStack::new();
        stack.push(1);
        stack.push(2);
        stack.push(3);

        assert_eq!(stack.pop(), Some(3));
        assert_eq!(stack.pop(), Some(2));
        assert_eq!(stack.pop(), Some(1));
        assert_eq!(stack.pop(), None);
    }

    #[test]
    fn test_concurrent_stack_multithreaded() {
        let stack = Arc::new(ConcurrentStack::new());
        let mut handles = vec![];

        // Spawn producer threads
        for i in 0..10 {
            let stack = Arc::clone(&stack);
            handles.push(thread::spawn(move || {
                for j in 0..100 {
                    stack.push(i * 100 + j);
                }
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }

        assert_eq!(stack.len(), 1000);

        // Spawn consumer threads
        let consumed = Arc::new(AtomicUsize::new(0));
        let mut handles = vec![];

        for _ in 0..10 {
            let stack = Arc::clone(&stack);
            let consumed = Arc::clone(&consumed);
            handles.push(thread::spawn(move || {
                while stack.pop().is_some() {
                    consumed.fetch_add(1, Ordering::Relaxed);
                }
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }

        assert_eq!(consumed.load(Ordering::Relaxed), 1000);
        assert!(stack.is_empty());
    }

    #[test]
    fn test_try_write_would_block() {
        let cell = ConcurrentCell::new(42);
        let _guard = cell.write().unwrap();
        assert!(matches!(cell.try_write(), Err(ConcurrentCellError::WouldBlock)));
    }

    #[test]
    fn test_try_read_would_block() {
        let cell = ConcurrentCell::new(42);
        let _guard = cell.write().unwrap();
        assert!(matches!(cell.try_read(), Err(ConcurrentCellError::WouldBlock)));
    }

    #[test]
    fn test_into_inner() {
        let cell = ConcurrentCell::new(String::from("hello"));
        let value = cell.into_inner();
        assert_eq!(value, "hello");
    }
}

fn main() {
    use std::sync::Arc;
    use std::thread;

    // Demo: ConcurrentCell
    println!("=== ConcurrentCell Demo ===");
    let cell = Arc::new(ConcurrentCell::new(0i64));
    let mut handles = vec![];

    for id in 0..4 {
        let cell = Arc::clone(&cell);
        handles.push(thread::spawn(move || {
            for _ in 0..1000 {
                let mut guard = cell.write().unwrap();
                *guard += 1;
                drop(guard);
            }
            println!("Thread {} finished writing", id);
        }));
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let guard = cell.read().unwrap();
    println!("Final value: {} (expected 4000)", *guard);
    drop(guard);

    // Demo: ConcurrentStack
    println!("\n=== ConcurrentStack Demo ===");
    let stack = Arc::new(ConcurrentStack::new());
    let mut handles = vec![];

    for id in 0..4 {
        let stack = Arc::clone(&stack);
        handles.push(thread::spawn(move || {
            for i in 0..100 {
                stack.push(id * 100 + i);
            }
            println!("Producer {} finished", id);
        }));
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("Stack length: {}", stack.len());

    let mut count = 0;
    while stack.pop().is_some() {
        count += 1;
    }
    println!("Popped {} items", count);
}